function Footer() {
    return (
        <>
        <div className="bg-gray-900">
           
            <div className=' grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 text-center p-2 text-sm '>
                <span className='text-white pt-10'>@{new Date().getFullYear()} All Right Reserved</span>
              
            </div>
</div>
        </>
    )
}

export default Footer
